function lesson(d: Partial<FdeDay> & { day: number; month: FdeDay["month"]; weekInMonth: FdeDay["weekInMonth"]; capstoneProgress: number }): FdeDay {
  return { kind: "lesson", ...d };
}

function rest(day: number, month: FdeDay["month"], weekInMonth: FdeDay["weekInMonth"], capstoneProgress: number): FdeDay {
  return { day, month, weekInMonth, kind: "rest", capstoneProgress };
}

function capstone(day: number, month: FdeDay["month"], weekInMonth: FdeDay["weekInMonth"], capstoneProgress: number, dsa?: FdeDay["dsa"], dsaTier?: string): FdeDay {
  return { day, month, weekInMonth, kind: "capstone", capstoneProgress, dsa, dsaTier };
}

