export function getDay(day: number): FdeDay | undefined {
  return FDE_DAYS.find((d) => d.day === day);
}

export function getMonthMeta(month: 1 | 2 | 3): FdeMonthMeta | undefined {
  return FDE_MONTHS.find((m) => m.month === month);
}

export function getCapstone(month: 1 | 2 | 3): FdeCapstone | undefined {
  return FDE_CAPSTONES.find((c) => c.month === month);
}
